import{_ as s,o as a,c as e,an as t}from"./chunks/framework.uF7fbnAT.js";const c=JSON.parse('{"title":"Frequently asked questions","description":"","frontmatter":{},"headers":[],"relativePath":"getting-started/faq.md","filePath":"getting-started/faq.md","lastUpdated":null}'),n={name:"getting-started/faq.md"};function o(h,i,r,l,d,p){return a(),e("div",null,[...i[0]||(i[0]=[t('<h1 id="faq" tabindex="-1">Frequently asked questions <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;Frequently asked questions {#faq}&quot;">​</a></h1><p>Short answers to the questions this package tends to raise. For a full walkthrough see <a href="/previews/PR91/getting-started/tutorials/composing-distributions#composing-distributions">Composing distributions</a>, and for the verb map see the <a href="/previews/PR91/getting-started/concepts#concepts">Concepts</a> page.</p><h2 id="Where-did-censoring-go?" tabindex="-1">Where did censoring go? <a class="header-anchor" href="#Where-did-censoring-go?" aria-label="Permalink to &quot;Where did censoring go? {#Where-did-censoring-go?}&quot;">​</a></h2><p>ComposedDistributions is the generic composition layer, split out from <a href="https://github.com/EpiAware/CensoredDistributions.jl" target="_blank" rel="noreferrer">CensoredDistributions.jl</a>. It composes any <code>Distributions.jl</code> <code>UnivariateDistribution</code> and adds no censoring of its own. If you need primary-event censoring, interval censoring, or truncation of the observation process, use CensoredDistributions.jl, which builds its censored leaves on top of this composition algebra. Right-truncation of a plain leaf is still available through <code>truncated()</code> from Distributions.jl, since any leaf is an ordinary distribution.</p><h2 id="Why-does-rand-of-a-Resolve-or-Compete-return-a-single-number?" tabindex="-1">Why does <code>rand</code> of a <code>Resolve</code> or <code>Compete</code> return a single number? <a class="header-anchor" href="#Why-does-rand-of-a-Resolve-or-Compete-return-a-single-number?" aria-label="Permalink to &quot;Why does `rand` of a `Resolve` or `Compete` return a single number? {#Why-does-rand-of-a-Resolve-or-Compete-return-a-single-number?}&quot;">​</a></h2><p>A one_of node is a univariate marginal: its <code>rand</code> is the time to resolution, whichever outcome occurs, and its <code>logpdf</code> scores that time. To also learn which outcome occurred, use <a href="./@ref"><code>rand_outcome</code></a>, which returns an<code>(outcome, time)</code> pair.</p><div class="language-julia vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">julia</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">using</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> ComposedDistributions, Distributions, Random</span></span>\n<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">import</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> ComposedDistributions</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">:</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> rand_outcome</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">node </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> resolve</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">:death</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =&gt;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> (</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">Gamma</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1.5</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1.0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">), </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0.3</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">), </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">:recover</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =&gt;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> Gamma</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">2.0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1.5</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">))</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">rand</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">Xoshiro</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">), node), </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">rand_outcome</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">Xoshiro</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">), node)</span></span></code></pre></div><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;">(1.8400307468613506, (:death, 1.8400307468613506))</span></span></code></pre></div><p>The two share the same drawn time; <code>rand_outcome</code> just also names the outcome.</p><h2 id="How-do-I-get-the-total-delay-distribution-of-a-chain?" tabindex="-1">How do I get the total-delay distribution of a chain? <a class="header-anchor" href="#How-do-I-get-the-total-delay-distribution-of-a-chain?" aria-label="Permalink to &quot;How do I get the total-delay distribution of a chain? {#How-do-I-get-the-total-delay-distribution-of-a-chain?}&quot;">​</a></h2><p>A <a href="/previews/PR91/lib/public#ComposedDistributions.Sequential"><code>Sequential</code></a> chain models each step separately, and its <code>rand</code> returns the per-step record. To collapse the chain to the single distribution of its origin-to-final gap, use <a href="/previews/PR91/lib/public#ComposedDistributions.observed_distribution"><code>observed_distribution</code></a>, which convolves the steps into one delay.</p><div class="language-julia vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">julia</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">chain </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> sequential</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">:onset_admit</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =&gt;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> Gamma</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">2.0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1.0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">),</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    :admit_death</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =&gt;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> Gamma</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">3.0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1.0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">))</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">total </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> observed_distribution</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(chain)</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">mean</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(total)</span></span></code></pre></div><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;">5.0</span></span></code></pre></div><p>For two standalone delays that are not part of a tree, <a href="/previews/PR91/lib/public#ConvolvedDistributions.convolve_distributions"><code>convolve_distributions</code></a> gives their sum <code>X + Y</code> directly.</p><h2 id="How-do-I-fix-a-parameter-across-branches?" tabindex="-1">How do I fix a parameter across branches? <a class="header-anchor" href="#How-do-I-fix-a-parameter-across-branches?" aria-label="Permalink to &quot;How do I fix a parameter across branches? {#How-do-I-fix-a-parameter-across-branches?}&quot;">​</a></h2><p>Use <a href="/previews/PR91/lib/public#ComposedDistributions.shared"><code>shared</code></a> or <a href="/previews/PR91/lib/public#ComposedDistributions.tie"><code>tie</code></a> to make several leaves one free parameter. <a href="/previews/PR91/lib/public#ComposedDistributions.shared"><code>shared</code></a> tags a leaf where it is built; <a href="/previews/PR91/lib/public#ComposedDistributions.tie"><code>tie</code></a> walks an assembled tree to named leaves and ties them. Either way <a href="/previews/PR91/lib/public#ComposedDistributions.params_table"><code>params_table</code></a> then inventories the tied occurrences once under the shared tag rather than as separate parameters.</p><div class="language-julia vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">julia</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">d </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> compose</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">((incubation </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> Gamma</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">2.0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1.0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">),</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    onset_report </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> Gamma</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">2.0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1.0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)))</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">tied </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> tie</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(d, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">:incubation</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">:onset_report</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">; name </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> :delay</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">unique</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">params_table</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(tied)</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">.</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">edge)</span></span></code></pre></div><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;">1-element Vector{Symbol}:</span></span>\n<span class="line"><span style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;"> :delay</span></span></code></pre></div><h2 id="Why-is-my-logpdf-Inf?" tabindex="-1">Why is my <code>logpdf</code> <code>-Inf</code>? <a class="header-anchor" href="#Why-is-my-logpdf-Inf?" aria-label="Permalink to &quot;Why is my `logpdf` `-Inf`? {#Why-is-my-logpdf-Inf?}&quot;">​</a></h2><p>A composed <code>logpdf</code> is <code>-Inf</code> when a value falls outside a leaf&#39;s support. The commonest cause is a negative or zero value scored against a positive-support delay, such as a <code>Gamma</code> or <code>LogNormal</code>. When scoring a whole record, check that every value sits in its own leaf&#39;s support and that the record is laid out in the tree&#39;s event order (see <a href="/previews/PR91/lib/public#ComposedDistributions.event_names"><code>event_names</code></a>); a value in the wrong slot can land outside the leaf that scores it.</p><h2 id="How-do-I-fit-a-composed-distribution-to-data?" tabindex="-1">How do I fit a composed distribution to data? <a class="header-anchor" href="#How-do-I-fit-a-composed-distribution-to-data?" aria-label="Permalink to &quot;How do I fit a composed distribution to data? {#How-do-I-fit-a-composed-distribution-to-data?}&quot;">​</a></h2><p>A composed object is a <code>Distribution</code>, so its <code>logpdf</code> is the likelihood term you need, and scoring is automatic-differentiation friendly. Drop it into a <a href="https://github.com/TuringLang/Turing.jl" target="_blank" rel="noreferrer">Turing.jl</a> model, or any optimiser, exactly as you would any distribution; there is no package-specific fitting API. <a href="/previews/PR91/lib/public#ComposedDistributions.params_table"><code>params_table</code></a> gives the free-parameter inventory and <a href="/previews/PR91/lib/public#ComposedDistributions.build_priors"><code>build_priors</code></a> derives support-respecting priors to start from.</p><h2 id="Is-a-composed-distribution-really-a-Distribution?" tabindex="-1">Is a composed distribution really a <code>Distribution</code>? <a class="header-anchor" href="#Is-a-composed-distribution-really-a-Distribution?" aria-label="Permalink to &quot;Is a composed distribution really a `Distribution`? {#Is-a-composed-distribution-really-a-Distribution?}&quot;">​</a></h2><p>Yes. Every composer subtypes <code>Distributions.Distribution</code>, so <code>logpdf</code>, <code>rand</code>, <code>mean</code>, <code>var</code>, <code>cdf</code> (where defined) and the rest of the interface work unchanged, and a composed object drops into any code that expects a distribution.</p>',24)])])}const g=s(n,[["render",o]]);export{c as __pageData,g as default};
